import React, { useEffect, useState } from 'react';
import { useProperty } from '../../contexts/PropertyContext';
import SellerForm from './SellerForm';

const SellerManagement = () => {
  const { sellers, fetchSellers, deleteSeller, loading } = useProperty();
  const [showModal, setShowModal] = useState(false);
  const [editingSeller, setEditingSeller] = useState(null);
  const [deleteConfirm, setDeleteConfirm] = useState(null);

  useEffect(() => {
    fetchSellers();
  }, [fetchSellers]);

  const handleAdd = () => {
    setEditingSeller(null);
    setShowModal(true);
  };

  const handleEdit = (seller) => {
    setEditingSeller(seller);
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    try {
      await deleteSeller(id);
      setDeleteConfirm(null);
    } catch (error) {
      alert('Failed to delete seller');
    }
  };

  const handleFormClose = () => {
    setShowModal(false);
    setEditingSeller(null);
  };

  return (
    <div className="management-page">
      <div className="page-header">
        <h1 className="page-title">Seller Management</h1>
        <button className="btn btn-primary" onClick={handleAdd}>
          ➕ Add Seller
        </button>
      </div>

      {loading ? (
        <div className="loading">
          <div className="spinner"></div>
        </div>
      ) : sellers.length === 0 ? (
        <div className="no-data">
          <div className="no-data-icon">👥</div>
          <h3>No Sellers Found</h3>
          <p>Start by adding your first seller.</p>
        </div>
      ) : (
        <div className="table-container">
          <table className="data-table">
            <thead>
              <tr>
                <th>ID</th>
                <th>Name</th>
                <th>Email</th>
                <th>Phone</th>
                <th>Company</th>
                <th>Address</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {sellers.map(seller => (
                <tr key={seller.id}>
                  <td>{seller.id}</td>
                  <td>{seller.name}</td>
                  <td>{seller.email}</td>
                  <td>{seller.phone}</td>
                  <td>{seller.company}</td>
                  <td>{seller.address}</td>
                  <td>
                    <div className="table-actions">
                      <button 
                        className="btn-icon edit"
                        onClick={() => handleEdit(seller)}
                        title="Edit"
                      >
                        ✏️
                      </button>
                      <button 
                        className="btn-icon delete"
                        onClick={() => setDeleteConfirm(seller.id)}
                        title="Delete"
                      >
                        🗑️
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Seller Form Modal */}
      {showModal && (
        <SellerForm 
          seller={editingSeller} 
          onClose={handleFormClose}
        />
      )}

      {/* Delete Confirmation Modal */}
      {deleteConfirm && (
        <div className="modal-overlay">
          <div className="modal" style={{ maxWidth: '400px' }}>
            <div className="modal-header">
              <h2>Confirm Delete</h2>
              <button className="modal-close" onClick={() => setDeleteConfirm(null)}>
                ✕
              </button>
            </div>
            <div className="modal-body">
              <p>Are you sure you want to delete this seller? This action cannot be undone.</p>
            </div>
            <div className="modal-footer">
              <button 
                className="btn btn-outline" 
                onClick={() => setDeleteConfirm(null)}
              >
                Cancel
              </button>
              <button 
                className="btn btn-danger" 
                onClick={() => handleDelete(deleteConfirm)}
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SellerManagement;
